        navController.navigate("profile")  // Works but NavHost missing
    }) {
        Text("Go")
    }

    // 3. Wrong argument type
    composable(
        route = "detail/{id}",
        arguments = listOf(
            navArgument("id") { type = NavType.IntType }
        )
    ) { backStackEntry ->
        val id = backStackEntry.arguments?.getString("id")  // Wrong type!
    }

    // 4. No popUpTo
    Button(onClick = {
        navController.navigate("profile")  // Back stack grows infinitely
    }) {
